// TC004: Cost prediction chart displays data
// Generated by TestSprite MCP — Round 1
// Fixed: Round 1 discovered actual API signatures
// Category: Cost Prediction | Priority: Medium

import 'package:flutter_test/flutter_test.dart';
import 'package:maintlogic/core/utils/z_score_calculator.dart';

void main() {
  group('TC004: Cost Prediction', () {
    test('Z-score calculator computes mean and std correctly', () {
      final values = [100.0, 110.0, 105.0, 115.0, 108.0];
      final stats = ZScoreCalculator.computeMeanStd(values);

      expect(stats, isNotNull);
      final (mean, std) = stats!;
      expect(mean, closeTo(107.6, 0.1));
      expect(std, greaterThan(0));
    });

    test('Z-score calculator detects outliers', () {
      final values = [100.0, 110.0, 105.0, 500.0, 108.0]; // 500 is outlier
      final stats = ZScoreCalculator.computeMeanStd(values);

      expect(stats, isNotNull);
      final (mean, std) = stats!;
      final z = ZScoreCalculator.zScore(500.0, mean, std);

      expect(z.abs(), greaterThan(1.5), reason: 'Outlier should have high Z-score');
    });

    test('Z-score returns null for insufficient data', () {
      final stats = ZScoreCalculator.computeMeanStd([100.0]); // Only 1 value
      expect(stats, isNull);
    });

    test('Z-score returns null for empty list', () {
      final stats = ZScoreCalculator.computeMeanStd([]);
      expect(stats, isNull);
    });

    test('isOutlier requires N >= 30', () {
      final smallDataset = List.generate(10, (i) => 100.0 + i);
      final result = ZScoreCalculator.isOutlier(
        price: 200.0,
        historicalPrices: smallDataset,
      );
      expect(result, isNull, reason: 'Should return null for N < 30');
    });

    test('isOutlier works with sufficient data', () {
      final normalPrices = List.generate(40, (_) => 100.0);
      final result = ZScoreCalculator.isOutlier(
        price: 500.0,
        historicalPrices: normalPrices,
      );
      expect(result, isTrue, reason: '500 is an outlier when all others are 100');
    });

    test('isOutlier handles zero-variance data (all identical)', () {
      final identicalPrices = List.generate(40, (_) => 100.0);
      final result = ZScoreCalculator.isOutlier(
        price: 200.0,
        historicalPrices: identicalPrices,
      );
      expect(result, isTrue,
          reason: '200 deviates from constant 100 — must be flagged');
    });

    test('isOutlier returns false when price matches constant mean', () {
      final identicalPrices = List.generate(40, (_) => 100.0);
      final result = ZScoreCalculator.isOutlier(
        price: 100.0,
        historicalPrices: identicalPrices,
      );
      expect(result, isFalse,
          reason: '100 matches the constant — not an outlier');
    });

    test('isOutlier boundary: z-score exactly at threshold', () {
      // Build a 30-element dataset with known mean ≈ 0 and known std
      final prices = <double>[];
      // 29 values at -1.0
      prices.addAll(List.generate(29, (_) => -1.0));
      // 1 value at 29.0 → mean = 0, std = sqrt(30*900/29/30) ≈ sqrt(31) ≈ 5.57
      prices.add(29.0);
      final stats = ZScoreCalculator.computeMeanStd(prices)!;
      final (mean, std) = stats;
      // boundaryValue = mean + threshold * std → z = threshold exactly
      final boundaryValue = mean + 2.0 * std;
      // Build a SEPARATE history to test against (exclude boundaryValue)
      final history = List<double>.from(prices);
      // Test: boundary value against same history should yield z = 2.0
      final result = ZScoreCalculator.isOutlier(
        price: boundaryValue,
        historicalPrices: history,
        threshold: 2.0,
      );
      // With >=, z = 2.0 should be flagged as outlier
      expect(result, isTrue,
          reason: 'Exact boundary (z = 2.0) must be classified as outlier');
    });
  });
}
